import{_ as t,o as e,c as r,ae as o}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"Strava Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/grafana/strava-dashboard.md","filePath":"software-engineering/grafana/strava-dashboard.md"}'),i={name:"software-engineering/grafana/strava-dashboard.md"};function n(s,a,d,h,l,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="strava-dashboard" tabindex="-1">Strava Dashboard <a class="header-anchor" href="#strava-dashboard" aria-label="Permalink to &quot;Strava Dashboard&quot;">​</a></h1><h2 id="the-grafana-principle-doing-data-analytics-for-sport-activities-entirely-in-the-cloud-part-1" tabindex="-1">The Grafana Principle: Doing Data Analytics for Sport Activities entirely in the Cloud (Part 1) <a href="#edb6" id="edb6"></a> <a class="header-anchor" href="#the-grafana-principle-doing-data-analytics-for-sport-activities-entirely-in-the-cloud-part-1" aria-label="Permalink to &quot;The Grafana Principle: Doing Data Analytics for Sport Activities entirely in the Cloud (Part 1) &lt;a href=&quot;#edb6&quot; id=&quot;edb6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><h3 id="monitoring-and-analysing-the-training-activities-for-you-and-your-team-is-easy-even-without-programming-knowledge" tabindex="-1">Monitoring and Analysing the Training Activities for you and your Team is easy even without Programming Knowledge <a href="#161c" id="161c"></a> <a class="header-anchor" href="#monitoring-and-analysing-the-training-activities-for-you-and-your-team-is-easy-even-without-programming-knowledge" aria-label="Permalink to &quot;Monitoring and Analysing the Training Activities for you and your Team is easy even without Programming Knowledge &lt;a href=&quot;#161c&quot; id=&quot;161c&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><img src="https://miro.medium.com/max/700/0*2FQ23LJelsBEIfOg" alt=""></p><p>Photo by <a href="https://unsplash.com/@kmuza" target="_blank" rel="noreferrer">Carlos Muza</a> on <a href="https://unsplash.com" target="_blank" rel="noreferrer">Unsplash</a></p><h3 id="introduction" tabindex="-1">Introduction <a href="#2feb" id="2feb"></a> <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction &lt;a href=&quot;#2feb&quot; id=&quot;2feb&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://squeezer44.medium.com/the-grafana-principle-doing-data-analytics-for-sport-activities-entirely-in-the-cloud-part-1-4d89ed9bbcb0" target="_blank" rel="noreferrer"> Great article from Medium</a></p><p>Imagine the situation: you often train cycling and do it in a team, and want to evaluate and show your training activities and those of your teammates on a dashboard.<br> And unfortunately, you neither have any programming skills nor a lot of money. So how can you solve the problem?</p><p>By reading this article and the next one, you’ll find out a way to escape this dilemma and create a dashboard without any programming skills.<br> You can’t do all cool data science stuff, but you can present a remarkable dashboard for yourself and your teammates.</p><p>You need two things for it: A Strava account and a Grafana login.</p><h3 id="goal" tabindex="-1">Goal <a href="#404b" id="404b"></a> <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal &lt;a href=&quot;#404b&quot; id=&quot;404b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Let’s first have a look into the serverless approach, which is fully running in the cloud.<br> This supports a better technical overview, is fun and gives us a functional process, which can be used for own purposes.</p><h3 id="a-graphic-describes-the-process-as-it-s-best" tabindex="-1">A Graphic describes the process as it’s best <a href="#8731" id="8731"></a> <a class="header-anchor" href="#a-graphic-describes-the-process-as-it-s-best" aria-label="Permalink to &quot;A Graphic describes the process as it’s best &lt;a href=&quot;#8731&quot; id=&quot;8731&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>In general, the process chain can be divided into three different steps:</p><ol><li>DataInput<br> Any device with a GPS and access to the internet can track your activity and upload the data afterwards to the cloud.<br> I’m currently using a mobile app at my cell phone for that.</li><li>DataProcessing<br> After the data were uploaded, they will be processed. This is done by Strava automatically and is a precondition for getting the results.<br> Strava presents the results on a dashboard, which is accessible either via cell phone (after the Strava app is opened) or with your personal computer via an internet browser.</li><li>Dashboarding<br> Dashboards, sometimes called IT dashboards, are single screens in which various critical pieces of information are placed in the form of panels.<br> Each panel contains a piece of information, all panels together are called as dashboard.<br> Strava is presenting a standardized dashboard, which I’m using only to check whether my data were properly uploaded and processed.<br> It is less suitable for visualizing an analysis of personal performance data.<br> In any case, it is unsuitable to visualize the data of a team on one and the same dashboard. And that is ultimately a prerequisite for being able to compare the performance data within a team.</li></ol><p>Let’s have a look on the overview first:</p><p><img src="https://miro.medium.com/proxy/1*YST0NZvT2Fp637lLuaC-5Q.png" alt="grafik.png"></p><h3 id="starting-position-and-optimized-result" tabindex="-1">Starting Position and optimized Result <a href="#79c7" id="79c7"></a> <a class="header-anchor" href="#starting-position-and-optimized-result" aria-label="Permalink to &quot;Starting Position and optimized Result &lt;a href=&quot;#79c7&quot; id=&quot;79c7&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>My starting point is Strava: it is showing me this on my dashboard:</p><p><img src="https://miro.medium.com/proxy/1*6j23cftX1qTgevNlprXGrw.png" alt="grafik.png"></p><p>It is easy to understand that no analytical knowledge can be gained from this at a glance. It is just a tabular representation of my performance data — nothing else.</p><p>I believe this makes it clear that it could be far more optimal than what is shown on the standardized Strava dashboard.<br> It is relatively easy to build a dashboard in just a few steps and does not require any programming knowledge. We will use the Grafana principle for our purposes and see how this works:</p><p><img src="https://miro.medium.com/proxy/1*3_frxx8F6aDRhGLoH-iizg.png" alt="grafik.png"></p><p>I believe this makes it clear that it is far more optimal than what is shown on the standardized Strava dashboard.</p><h3 id="used-tools" tabindex="-1">Used Tools <a href="#dc72" id="dc72"></a> <a class="header-anchor" href="#used-tools" aria-label="Permalink to &quot;Used Tools &lt;a href=&quot;#dc72&quot; id=&quot;dc72&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>To achieve that, we need only three tools. All of them are available with no additional costs in a basic version:</p><ul><li><strong>Strava App on your mobile</strong>: Could be an app on your mobile or another mobile device which has a GPS on board and is able to track your sport activity.</li><li><strong>Strava Web Account</strong>: Strava is a service that allows athletes to track and analyze their workouts and training sessions. It’s widely used for activities such as running and cycling (URL: <a href="https://www.strava.com/dashboard)." target="_blank" rel="noreferrer">https://www.strava.com/dashboard).</a></li><li><strong>Grafana Account</strong>: Grafana is open-source visualization and analytics software. It allows you to query, visualize, alert on, and explore your metrics no matter where they are stored (URL: <a href="https://grafana.com/)." target="_blank" rel="noreferrer">https://grafana.com/).</a></li></ul><h3 id="precondition-create-a-grafana-account-and-connect-it-with-strava" tabindex="-1">Precondition: Create a Grafana Account and connect it with Strava <a href="#8841" id="8841"></a> <a class="header-anchor" href="#precondition-create-a-grafana-account-and-connect-it-with-strava" aria-label="Permalink to &quot;Precondition: Create a Grafana Account and connect it with Strava &lt;a href=&quot;#8841&quot; id=&quot;8841&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>First things first: as a precondition, I need a Grafana account. This is easy to achieve by registering and login.<br> In case you’re using the Free-plan as me you should see something like that at your Grafana home screen after login:</p><p><img src="https://miro.medium.com/proxy/1*cbLIKfdOIwvCtlQfHd54mQ.png" alt="grafik.png"></p><p>After that, we need to edit the configuration of our Grafana environment by adding our Strava API as an external data source.<br> To do so, we click inside the left vertical navigation bar at Configuration/Data sources:</p><p><img src="https://miro.medium.com/proxy/1*hy6BJG3IpjTMPq2Faxbzkg.png" alt="grafik.png"></p><p>As next, we can see the configuration page at Grafana and press the button Add data source.<br> We need to search for strava:</p><p><img src="https://miro.medium.com/proxy/1*FbpsNLC9QkRm31yrC63Yqg.png" alt="grafik.png"></p><p>A left mouse click at this entry will bring us one step ahead: we now can connect our Grafana environment with Strava. To get it done we need our Client ID and the Client Secret at Strava, paste it in and press the button Connect with Strava:</p><p><img src="https://miro.medium.com/proxy/1*4bIwUWFxsZJoGf_2b_7gSw.png" alt="grafik.png"></p><p>As next a new windows opens. Strava is asking me to authorize my Grafana App:</p><p><img src="https://miro.medium.com/proxy/1*b46ldJqkxEnoQrLWejomqg.png" alt="grafik.png"></p><p>After I pressed the button Authorize the process was completed, and I will be redirected into my Grafana environment and can test the connection by pressing Save &amp; Test:</p><p><img src="https://miro.medium.com/proxy/1*SAItSjdzttDeymlKvHapUA.png" alt="grafik.png"></p><p>And that’s it!<br> This finished the necessary authorization process for the Grafana environment. We are now able to read the data via the Strava API.</p><h3 id="conclusion" tabindex="-1">Conclusion <a href="#416b" id="416b"></a> <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion &lt;a href=&quot;#416b&quot; id=&quot;416b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>With this article, we have laid the baseline for building a dashboard with Grafana.<br> After we took a technical overview, have seen the starting position and our goal, we laid the baseline to go ahead:<br> we created a Grafana account, connect it with Strava, authorize and test it.</p><h3 id="that-s-next" tabindex="-1">That’s next <a href="#f668" id="f668"></a> <a class="header-anchor" href="#that-s-next" aria-label="Permalink to &quot;That’s next &lt;a href=&quot;#f668&quot; id=&quot;f668&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>So far everything has been hard work and not really exciting. But this will change with the next upcoming article.<br> In this, we will see, how we can easily gather the data and build something meaningful and interesting of it with a Grafana dashboard.</p><p>\\</p>',46)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
